import app from 'flarum/common/app';
const base = () => app.forum.attribute('apiUrl');
export function listRules() {
  return app.request({
    method: 'GET',
    url: "".concat(base(), "/janitor/rules")
  });
}
export function saveRule(data, id) {
  return app.request({
    method: id ? 'PATCH' : 'POST',
    url: "".concat(base(), "/janitor/rules").concat(id ? '/' + id : ''),
    body: {
      data
    }
  });
}
export function deleteRule(id) {
  return app.request({
    method: 'DELETE',
    url: "".concat(base(), "/janitor/rules/").concat(id)
  });
}
export function runRule(id, dry) {
  return app.request({
    method: 'POST',
    url: "".concat(base(), "/janitor/rules/").concat(id, "/run?dry=").concat(dry ? 1 : 0)
  });
}
export function listLog() {
  return app.request({
    method: 'GET',
    url: "".concat(base(), "/janitor/log")
  });
}
flarum.reg.add('ernestdefoe-janitor', 'common/api', { listRules: listRules,saveRule: saveRule,deleteRule: deleteRule,runRule: runRule,listLog: listLog, });